package sn.gestionimmobiliere.backend.receipt.domain;import java.time.Instant;import java.util.UUID;import jakarta.persistence.*;@Entity @Table(name="receipts")public class Receipt{@Id private UUID id;@Column(name="organization_id")private UUID organizationId;@Column(name="rent_charge_id")private UUID rentChargeId;@Column(name="receipt_number")private String receiptNumber;@Column(name="issued_at")private Instant issuedAt;protected Receipt(){}public Receipt(UUID id,UUID org,UUID charge,String number,Instant at){this.id=id;organizationId=org;rentChargeId=charge;receiptNumber=number;issuedAt=at;}public UUID getId(){return id;}public UUID getRentChargeId(){return rentChargeId;}public String getReceiptNumber(){return receiptNumber;}public Instant getIssuedAt(){return issuedAt;}}
